{"code": "import json

lf_books_file = locals()['var_functions.query_db:12']
with open(lf_books_file, 'r') as f:
    lf_books = json.load(f)

print(f'Found {len(lf_books)} Literature & Fiction books')

english_lf_books = []
for book in lf_books:
    details = book.get('details', '').lower()
    if 'english' in details:
        english_lf_books.append({
            'book_id': book['book_id'],
            'title': book['title'],
            'categories': book['categories'],
            'details': book['details']
        })

print(f'Found {len(english_lf_books)} English Literature & Fiction books')

reviews_file = locals()['var_functions.query_db:10']
with open(reviews_file, 'r') as f:
    reviews = json.load(f)

print(f'Found {len(reviews)} total review records')

# Create mapping from purchase_id to book_id
purchase_book_map = {}
for book in lf_books:
    purchase_id = book['book_id'].replace('bookid_', 'purchaseid_')
    purchase_book_map[purchase_id] = book['book_id']

print(f'Created mapping for {len(purchase_book_map)} books')

# Filter reviews for our English Literature & Fiction books
english_book_ids = {book['book_id'] for book in english_lf_books}
filtered_reviews = []
for review in reviews:
    purchase_id = review['purchase_id']
    if purchase_id in purchase_book_map:
        book_id = purchase_book_map[purchase_id]
        if book_id in english_book_ids:
            filtered_reviews.append({
                'book_id': book_id,
                'rating': float(review['rating'])
            })

print(f'Found {len(filtered_reviews)} reviews for English Literature & Fiction books')

# Calculate average rating per book
from collections import defaultdict
book_ratings = defaultdict(list)
for review in filtered_reviews:
    book_ratings[review['book_id']].append(review['rating'])

perfect_books = []
for book_id, ratings in book_ratings.items():
    if len(ratings) > 0:
        avg_rating = sum(ratings) / len(ratings)
        if abs(avg_rating - 5.0) < 0.01:  # Allow for floating point issues
            book_info = next((b for b in english_lf_books if b['book_id'] == book_id), None)
            if book_info:
                perfect_books.append({
                    'title': book_info['title'],
                    'book_id': book_id,
                    'avg_rating': avg_rating,
                    'review_count': len(ratings),
                    'categories': book_info['categories']
                })

perfect_books_sorted = sorted(perfect_books, key=lambda x: x['review_count'], reverse=True)

print('__RESULT__:')
print(json.dumps(perfect_books_sorted, indent=2))"}

